void solve(int CASE)
{
	int n, k; cin >> n >> k;
	var a = vector<int>(n + 1);
	fa(i, 1, n)cin >> a[i];
	var check = [&](int mid)->bool {
		var pre = vector<int>(n + 1);
		fa(i, 1, k) {
			pre[i] = pre[i - 1];
			if (a[i] >= mid)pre[i]++;
			else pre[i]--;
		}
		if (pre[k] >= 1)return 1;
		int mnpre = 0;
		fa(i, k + 1, n) {
			pre[i] = pre[i - 1];
			if (a[i] >= mid)pre[i]++;
			else pre[i]--;
			mnpre = min(pre[i - k], mnpre);
			int now = pre[i] - mnpre;
			if (now >= 1)return 1;
		}
		return 0;
		};
	int l = 1, r = n, ans = 0;
	while (l <= r) {
		int mid = l + r >> 1;
		if (check(mid)) {
			l = mid + 1;
			ans = mid;
		}
		else r = mid - 1;
	}
